class Solution:
    def heightChecker(self, heights):
        expected = sorted(heights)
        count = 0
        for i in range(len(heights)):
            if heights[i] != expected[i]:
                count += 1
        return count

solutions.python:
class Solution:
    def heightChecker(self, heights):
        return sum(1 for a, b in zip(heights, sorted(heights)) if a != b)

